#include <stdio.h>
#include <stdlib.h>

#define MAXN 1005
#define MAXM 1000000  // enough for 2 * N*(N-1)/2 when N=1000

typedef struct Edge {int to; struct Edge* next;} Edge;
Edge edges[MAXM];
Edge* head[MAXN];
int edgeCnt;

void addEdge(int u, int v) {
    edges[edgeCnt].to = v;
    edges[edgeCnt].next = head[u];
    head[u] = &edges[edgeCnt++];
    edges[edgeCnt].to = u;
    edges[edgeCnt].next = head[v];
    head[v] = &edges[edgeCnt++];
}

int timer;
int tin[MAXN];
int low[MAXN];
int visited[MAXN];
int bridges;

void dfs(int v, int p) {
    visited[v] = 1;
    tin[v] = low[v] = ++timer;
    for (Edge* e = head[v]; e; e = e->next) {
        int to = e->to;
        if (to == p) continue;
        if (visited[to]) {
            if (tin[to] < low[v]) low[v] = tin[to];
        } else {
            dfs(to, v);
            if (low[to] < low[v]) low[v] = low[to];
            if (low[to] > tin[v]) bridges++;
        }
    }
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        for (int i = 1; i <= N; ++i) head[i] = NULL;
        edgeCnt = 0;
        for (int i = 0; i < M; ++i) {
            int a, b; scanf("%d %d", &a, &b);
            addEdge(a, b);
        }
        for (int i = 1; i <= N; ++i) visited[i] = 0;
        timer = 0; bridges = 0;
        int components = 0;
        for (int i = 1; i <= N; ++i) {
            if (!visited[i]) {
                components++;
                dfs(i, -1);
            }
        }
        if (components == 1) printf("%d\n", bridges);
        else printf("0\n");
    }
    return 0;
}

