import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final BufferedInputStream in = new BufferedInputStream(System.in);
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
    static int timer, bridges;
    static int[] tin, low, visited;
    static List<Integer>[] g;
    static void dfs(int v, int p){
        visited[v]=1; tin[v]=low[v]=++timer;
        for(int to: g[v]){
            if(to==p) continue;
            if(visited[to]==1){
                low[v]=Math.min(low[v], tin[to]);
            }else{
                dfs(to, v);
                low[v]=Math.min(low[v], low[to]);
                if(low[to]>tin[v]) bridges++;
            }
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            int M = fs.nextInt();
            g = new ArrayList[N+1];
            for(int i=1;i<=N;i++) g[i]=new ArrayList<>();
            for(int i=0;i<M;i++){
                int a = fs.nextInt();
                int b = fs.nextInt();
                g[a].add(b);
                g[b].add(a);
            }
            tin = new int[N+1];
            low = new int[N+1];
            visited = new int[N+1];
            timer = 0; bridges = 0; int components = 0;
            for(int i=1;i<=N;i++) if(visited[i]==0){
                components++;
                dfs(i, -1);
            }
            if(components==1) sb.append(bridges).append('\n');
            else sb.append(0).append('\n');
        }
        System.out.print(sb.toString());
    }
}

