const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
function nextInt(){return Number(input[idx++]);}
const T = nextInt();
let results = [];
for(let tc=0; tc<T; ++tc){
  const N = nextInt();
  const M = nextInt();
  const g = Array.from({length:N+1},()=>[]);
  for(let i=0;i<M;++i){
    const a = nextInt();
    const b = nextInt();
    g[a].push(b);
    g[b].push(a);
  }
  const tin = new Array(N+1).fill(0);
  const low = new Array(N+1).fill(0);
  const visited = new Array(N+1).fill(false);
  let timer = 0, bridges = 0, components = 0;
  function dfs(v, p){
    visited[v] = true;
    tin[v] = low[v] = ++timer;
    for(const to of g[v]){
      if(to===p) continue;
      if(visited[to]){
        low[v] = Math.min(low[v], tin[to]);
      }else{
        dfs(to, v);
        low[v] = Math.min(low[v], low[to]);
        if(low[to] > tin[v]) bridges++;
      }
    }
  }
  for(let i=1;i<=N;++i){
    if(!visited[i]){components++; dfs(i, -1);}
  }
  results.push(components===1 ? bridges : 0);
}
